import{_ as i,o as a,c as s,a2 as o}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Servizi","description":"","frontmatter":{},"headers":[],"relativePath":"it/api/services.md","filePath":"it/api/services.md"}'),n={name:"it/api/services.md"};function t(r,e,l,c,d,p){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="servizi" tabindex="-1">Servizi <a class="header-anchor" href="#servizi" aria-label="Permalink to &quot;Servizi&quot;">​</a></h1><p>Tutti i servizi di Clearance vivono in <code>src/Services/</code> e vengono risolti dal container, es. <code>app(ContextService::class)</code>. Sono il livello a cui rivolgersi da controller, policy, e job — ovunque il modello <code>User</code> potrebbe non usare il trait <code>HasClearance</code>.</p><h2 id="contextservice" tabindex="-1"><code>ContextService</code> <a class="header-anchor" href="#contextservice" aria-label="Permalink to &quot;`ContextService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\ContextService</code> (<code>src/Services/ContextService.php</code>) è il motore dietro l&#39;autorizzazione contestuale. Sia la <a href="/clearance-docs/it/api/facade.html">facade <code>Clearance</code></a> sia il trait <code>HasClearance</code> delegano ad esso.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\ContextService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ContextService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">canIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasPermissionIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// alias</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasRoleIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;manager&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveFor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Collection of all effective permission names</span></span></code></pre></div><p><code>resolveFor()</code> costruisce il suo risultato usando una precedenza a 3 fonti:</p><ol><li>Concessioni di ruolo contestuali</li><li>Concessioni di ruolo globali</li><li>Override per contesto (<code>forced_on</code> aggiunge, <code>forced_off</code> vince sempre)</li></ol><p>Vedi <a href="/clearance-docs/it/features/contextual-authorization.html">Contextual Authorization</a> per la spiegazione concettuale di questa precedenza.</p><h2 id="roleservice" tabindex="-1"><code>RoleService</code> <a class="header-anchor" href="#roleservice" aria-label="Permalink to &quot;`RoleService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\RoleService</code> (<code>src/Services/RoleService.php</code>) gestisce i ruoli ceiling.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\RoleService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole, $parentRole);</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">removeParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole);</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Metodo</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>setParent($childRole, $parentRole)</code></td><td>Imposta un ceiling: i permessi in eccesso su <code>$childRole</code> oltre il set del genitore vengono rimossi silenziosamente. Lancia <code>ClearanceScopeViolationException</code> se il figlio è già un genitore, o il genitore è già un figlio.</td></tr><tr><td><code>removeParent($childRole)</code></td><td>Rimuove la relazione di ceiling.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Un ceiling rimuove soltanto — non concede mai. Un ruolo genitore permissivo non dà di per sé alcun permesso al figlio. La rimozione di un permesso da un ruolo genitore propaga automaticamente quella rimozione a ogni ruolo figlio.</p></div><p>Vedi <a href="/clearance-docs/it/features/roles.html">Roles</a> per il concetto di ruolo ceiling più in dettaglio.</p><h2 id="permissionservice" tabindex="-1"><code>PermissionService</code> <a class="header-anchor" href="#permissionservice" aria-label="Permalink to &quot;`PermissionService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\PermissionService</code> (<code>src/Services/PermissionService.php</code>) supporta il CRUD del pannello Permessi.</p><p>Applica la convenzione di naming <code>group-action</code>, controllata dalle chiavi di configurazione <code>enforce_naming_convention</code> e <code>naming_separator</code>, e protegge il namespace di permessi <code>clearance-*</code> dall&#39;essere creato, rinominato, o eliminato al di fuori del flusso di installazione.</p><h2 id="guardservice" tabindex="-1"><code>GuardService</code> <a class="header-anchor" href="#guardservice" aria-label="Permalink to &quot;`GuardService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\GuardService</code> (<code>src/Services/GuardService.php</code>) supporta il CRUD del pannello Guardie.</p><p>Inietta le guardie basate su database in <code>auth.guards</code> all&#39;avvio, filtrate dalla chiave di configurazione <code>allowed_guard_drivers</code> — un driver non elencato viene saltato con un avviso nel log invece di corrompere la configurazione di autenticazione.</p><h2 id="metaservice" tabindex="-1"><code>MetaService</code> <a class="header-anchor" href="#metaservice" aria-label="Permalink to &quot;`MetaService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\MetaService</code> (<code>src/Services/MetaService.php</code>) legge e scrive <code>clr_meta</code> (nome visualizzato, descrizione, icona SVG sanitizzata, colore) per un soggetto ruolo o guardia. Supporta l&#39;editor dei metadati di visualizzazione del pannello Impostazioni.</p><p>Le icone SVG passano attraverso <code>Rivalex\\Clearance\\Support\\SvgSanitizer</code> (un sanitizzatore allow-list) sia prima della memorizzazione sia in fase di rendering.</p><h2 id="userclearanceservice" tabindex="-1"><code>UserClearanceService</code> <a class="header-anchor" href="#userclearanceservice" aria-label="Permalink to &quot;`UserClearanceService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\UserClearanceService</code> (<code>src/Services/UserClearanceService.php</code>) supporta il pannello del modulo Utenti:</p><ul><li>Assegnazione di ruolo globale</li><li>Assegnazione di ruolo contestuale (tramite <code>UserRoleContext</code>)</li><li>Override dei permessi per contesto (tramite <code>UserContextPermissionOverride</code>, <code>forced_on</code> / <code>forced_off</code>)</li><li>Rimozione delle assegnazioni, che propaga l&#39;eliminazione degli override</li></ul><p>Applica un ceiling di privilegio: un attore non <code>super_admin</code> non può modificare le proprie assegnazioni, e non può concedere un permesso che non detiene lui stesso. Vedi <a href="/clearance-docs/it/features/super-admin.html">Super Admin</a> e <a href="/clearance-docs/it/features/users.html">Users</a>.</p><h2 id="eccezioni" tabindex="-1">Eccezioni <a class="header-anchor" href="#eccezioni" aria-label="Permalink to &quot;Eccezioni&quot;">​</a></h2><p>Tutte in <code>src/Exceptions/</code>:</p><table tabindex="0"><thead><tr><th>Eccezione</th><th>Lanciata quando</th></tr></thead><tbody><tr><td><code>ClearanceConfigException</code></td><td>Viene letto un valore non valido o mal configurato di <code>config/clearance.php</code> (es. un <code>naming_separator</code> non valido).</td></tr><tr><td><code>ClearanceNamingException</code></td><td>Un nome di permesso viola la convenzione di naming <code>group-action</code> mentre l&#39;applicazione è attiva.</td></tr><tr><td><code>ClearanceProtectedResourceException</code></td><td>Viene tentata una modifica a un permesso <code>clearance-*</code> protetto, o a una risorsa bloccata, al di fuori del flusso di installazione.</td></tr><tr><td><code>ClearanceScopeViolationException</code></td><td>Una relazione di ruolo ceiling non valida (un genitore che cerca di diventare figlio, o viceversa), o un disallineamento di ambito.</td></tr></tbody></table><h2 id="vedi-anche" tabindex="-1">Vedi anche <a class="header-anchor" href="#vedi-anche" aria-label="Permalink to &quot;Vedi anche&quot;">​</a></h2><ul><li><a href="/clearance-docs/it/api/facade.html">Facade</a> — il wrapper in chiamate statiche attorno a <code>ContextService</code>.</li><li><a href="/clearance-docs/it/api/traits-directives.html">Traits &amp; Directives</a> — gli equivalenti in metodi di istanza e direttive Blade.</li><li><a href="/clearance-docs/it/api/artisan-commands.html">Artisan Commands</a> — <code>clearance:install</code> e <code>clearance:backfill</code>, che generano i dati su cui operano questi servizi.</li></ul>',32)])])}const u=i(n,[["render",t]]);export{k as __pageData,u as default};
